#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-03-11

# Spike: Test 4 approaches to detect skill consultation from claude -p output
# Run this OUTSIDE of Claude Code (raw terminal), requires CC Max license
#
# Usage: ./tests/evals/scripts/spike-trigger-detection.sh
set -uo pipefail

# Ensure we're not inside a Claude Code session
unset CLAUDECODE 2>/dev/null || true

PLUGIN_DIR="plugins/ork"
CLAUDE_FLAGS="--dangerously-skip-permissions --max-turns 1"
PROMPT="commit my changes"
SKILL_NAME="commit"
RESULTS_DIR="/tmp/spike-trigger-detection"
mkdir -p "$RESULTS_DIR"

echo "=== Spike: Trigger Detection Methods ==="
echo "Prompt: '$PROMPT'"
echo "Expected skill: $SKILL_NAME"
echo ""

# ─── Option 1: stream-json output ───────────────────────────────────────────
echo "--- Option 1: --output-format stream-json ---"
claude -p "$PROMPT" \
  --plugin-dir "$PLUGIN_DIR" $CLAUDE_FLAGS \
  --output-format stream-json \
  > "$RESULTS_DIR/stream-json.jsonl" 2>"$RESULTS_DIR/stream-json.stderr"

echo "Lines: $(wc -l < "$RESULTS_DIR/stream-json.jsonl")"
echo "Skill mentions in stdout:"
grep -i "$SKILL_NAME\|skill\|tool_use\|Skill" "$RESULTS_DIR/stream-json.jsonl" | head -10 || echo "  (none)"
echo "Skill mentions in stderr:"
grep -i "$SKILL_NAME\|skill\|tool_use\|Skill" "$RESULTS_DIR/stream-json.stderr" | head -10 || echo "  (none)"
echo ""

# ─── Option 2: json output ─────────────────────────────────────────────────
echo "--- Option 2: --output-format json ---"
claude -p "$PROMPT" \
  --plugin-dir "$PLUGIN_DIR" $CLAUDE_FLAGS \
  --output-format json \
  > "$RESULTS_DIR/json.json" 2>"$RESULTS_DIR/json.stderr"

echo "JSON keys:"
python3 -c "
import json, sys
data = json.load(open('$RESULTS_DIR/json.json'))
if isinstance(data, dict):
    print('  Top-level keys:', list(data.keys()))
elif isinstance(data, list):
    print('  Array of', len(data), 'items')
    if data:
        print('  First item keys:', list(data[0].keys()) if isinstance(data[0], dict) else type(data[0]))
" 2>/dev/null || echo "  (not valid JSON)"
echo "Skill mentions:"
grep -i "$SKILL_NAME\|skill\|tool_use" "$RESULTS_DIR/json.json" | head -5 || echo "  (none)"
echo ""

# ─── Option 3: --debug stderr ──────────────────────────────────────────────
echo "--- Option 3: --debug flag ---"
claude -p "$PROMPT" \
  --plugin-dir "$PLUGIN_DIR" $CLAUDE_FLAGS \
  --debug \
  > "$RESULTS_DIR/debug-stdout.txt" 2>"$RESULTS_DIR/debug-stderr.txt"

echo "Stderr lines: $(wc -l < "$RESULTS_DIR/debug-stderr.txt")"
echo "Skill mentions in debug stderr:"
grep -i "$SKILL_NAME\|skill\|plugin\|invoke" "$RESULTS_DIR/debug-stderr.txt" | head -10 || echo "  (none)"
echo ""

# ─── Option 4: append-system-prompt ────────────────────────────────────────
echo "--- Option 4: --append-system-prompt ---"
claude -p "$PROMPT" \
  --plugin-dir "$PLUGIN_DIR" $CLAUDE_FLAGS \
  --append-system-prompt "IMPORTANT: At the very end of your response, add a line starting with '@@SKILLS_USED@@:' followed by a comma-separated list of skill names you consulted (from plugins). If none, write '@@SKILLS_USED@@: none'." \
  > "$RESULTS_DIR/append-prompt.txt" 2>"$RESULTS_DIR/append-prompt.stderr"

echo "Output:"
cat "$RESULTS_DIR/append-prompt.txt"
echo ""
echo "Skills detected:"
grep "@@SKILLS_USED@@" "$RESULTS_DIR/append-prompt.txt" || echo "  (marker not found)"
echo ""

# ─── Option 5: output signature (heuristic) ────────────────────────────────
echo "--- Option 5: Output signature detection ---"
# Run WITH plugin
claude -p "$PROMPT" \
  --plugin-dir "$PLUGIN_DIR" $CLAUDE_FLAGS \
  > "$RESULTS_DIR/with-plugin.txt" 2>/dev/null

# Run WITHOUT plugin
claude -p "$PROMPT" $CLAUDE_FLAGS \
  > "$RESULTS_DIR/without-plugin.txt" 2>/dev/null

echo "With plugin output length: $(wc -c < "$RESULTS_DIR/with-plugin.txt")"
echo "Without plugin output length: $(wc -c < "$RESULTS_DIR/without-plugin.txt")"
echo ""
echo "With plugin (first 500 chars):"
head -c 500 "$RESULTS_DIR/with-plugin.txt"
echo ""
echo "Without plugin (first 500 chars):"
head -c 500 "$RESULTS_DIR/without-plugin.txt"
echo ""

# ─── Summary ────────────────────────────────────────────────────────────────
echo ""
echo "=== All outputs saved to $RESULTS_DIR ==="
echo "Review each approach and pick the most reliable detection method."
echo ""
echo "Files:"
ls -la "$RESULTS_DIR/"
